const body = items[0].json.body || items[0].json;

const paper_text = (body.paper_text || '').substring(0, 30000);
const subject = body.subject || 'General';
const assessment_type = body.assessment_type || 'Assessment';
const mode = body.mode || 'A';
const num_questions = body.num_questions || '4';
const rubric_json = body.rubric_json || null;

let rubricContext = '';
if (rubric_json) {
  rubricContext = '\nRUBRIC:\n' + JSON.stringify(rubric_json, null, 2) + '\n\nEvaluate against this rubric\'s specific criteria and mark allocation.\n';
}

const prompt = `You are an expert academic evaluator. Evaluate this student paper and return ONLY valid JSON.

Paper details:
- Subject: ${subject}
- Assessment type: ${assessment_type}
- Mode: ${mode}
- Number of questions: ${num_questions}

${rubricContext}

Return this exact JSON structure:
{
  "overall_score": number (0-100),
  "knowledge_score": number (0-100),
  "critical_score": number (0-100),
  "application_score": number (0-100),
  "referencing_score": number (0-100),
  "structure_score": number (0-100),
  "ai_risk_score": number or null (0-100, only for Mode B),
  "report_html": "full HTML report with styling",
  "issues": [{"category":"...","severity":"critical|important|polish","what_issue":"...","where_in_paper":"...","why_chain":["..."],"root_cause":"...","how_to_fix":"...","who_notices":"...","description":"...","recommendation":"...","example_before":"...","example_after":"..."}],
  "strengths": [{"category":"...","what_well":"...","where_in_paper":"...","why_chain":["..."],"reusable_pattern":"...","how_it_helps":"...","who_notices":"..."}],
  "references": [{"citation":"...","source_type":"in_text|bibliography","matched":true|false,"issue_type":"..."}],
  "consistency": [{"location_a":"...","location_b":"...","description":"...","verdict":"consistent|inconsistent","explanation":"...","recommendation":"..."}]
}

The report_html should be a comprehensive evaluation report with:
- Executive summary with overall score
- Detailed scoring breakdown by category
- Key issues found with severity levels
- Strengths identified
- Reference audit results
- Actionable recommendations
- Use inline CSS for styling (amber/cream theme, clean academic look)

For Mode B (Turnitin Ready), also include AI detection risk analysis.

PAPER TEXT:
${paper_text}`;

return [{ json: { prompt } }];

const response = items[0].json;
let text = response.text || response.output || '';

if (!text && response.candidates && response.candidates.length > 0) {
  const parts = response.candidates[0].content.parts;
  if (parts && parts.length > 0) text = parts[0].text;
}

if (!text) {
  return [{ json: { error: 'AI evaluation failed to return results. Please try again.' } }];
}

let jsonStr = text.trim();
if (jsonStr.startsWith('```')) {
  jsonStr = jsonStr.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
}

const firstBrace = jsonStr.indexOf('{');
if (firstBrace > 0) jsonStr = jsonStr.substring(firstBrace);
if (!jsonStr.endsWith('}')) {
  const lastBrace = jsonStr.lastIndexOf('}');
  if (lastBrace > 0) jsonStr = jsonStr.substring(0, lastBrace + 1);
}

try {
  const parsed = JSON.parse(jsonStr);
  return [{ json: {
    overall_score: parsed.overall_score || 0,
    knowledge_score: parsed.knowledge_score || 0,
    critical_score: parsed.critical_score || 0,
    application_score: parsed.application_score || 0,
    referencing_score: parsed.referencing_score || 0,
    structure_score: parsed.structure_score || 0,
    ai_risk_score: parsed.ai_risk_score ?? null,
    report_html: parsed.report_html || '',
    issues: parsed.issues || [],
    strengths: parsed.strengths || [],
    references: parsed.references || [],
    consistency: parsed.consistency || []
  } }];
} catch (e) {
  return [{ json: { error: 'AI evaluation failed to return valid results. Please try again.' } }];
}
